package blindrsa

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/sha512"
	"encoding/base64"
	"encoding/hex"
	"math/big"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/vitalvas/kasper/mux"
)

func TestEndToEnd(t *testing.T) {
	priv, err := rsa.GenerateKey(rand.Reader, 2048)
	require.NoError(t, err)

	pub := &priv.PublicKey

	for _, variant := range allVariants() {
		t.Run(variant.String(), func(t *testing.T) {
			msg := []byte("full end-to-end test message")

			issueHandler, err := IssueHandler(IssuerConfig{
				Key:     priv,
				Variant: variant,
			})
			require.NoError(t, err)

			issuer := httptest.NewServer(issueHandler)
			defer issuer.Close()

			client, err := NewClient(ClientConfig{
				Key:           pub,
				Variant:       variant,
				TokenEndpoint: issuer.URL,
			})
			require.NoError(t, err)

			sig, state, err := client.ObtainSignature(context.Background(), msg)
			require.NoError(t, err)
			assert.Len(t, sig, keyLen(pub))

			inputMsg := state.InputMessage()
			err = Verify(variant, pub, inputMsg, sig)
			require.NoError(t, err)

			mw, err := VerifyMiddleware(MiddlewareConfig{
				Key:     pub,
				Variant: variant,
				MessageFunc: func(_ *http.Request) ([]byte, error) {
					return inputMsg, nil
				},
			})
			require.NoError(t, err)

			r := mux.NewRouter()
			r.HandleFunc("/resource", func(w http.ResponseWriter, _ *http.Request) {
				w.WriteHeader(http.StatusOK)
				w.Write([]byte("protected content"))
			}).Methods(http.MethodGet)
			r.Use(mw)

			req := httptest.NewRequest(http.MethodGet, "/resource", nil)
			req.Header.Set("Blind-Signature", base64.StdEncoding.EncodeToString(sig))

			w := httptest.NewRecorder()
			r.ServeHTTP(w, req)

			assert.Equal(t, http.StatusOK, w.Code)
			assert.Equal(t, "protected content", w.Body.String())

			req2 := httptest.NewRequest(http.MethodGet, "/resource", nil)
			w2 := httptest.NewRecorder()
			r.ServeHTTP(w2, req2)

			assert.Equal(t, http.StatusUnauthorized, w2.Code)
		})
	}
}

func TestEndToEndWithDifferentKeySizes(t *testing.T) {
	for _, bits := range []int{2048, 3072, 4096} {
		t.Run(keyName(bits), func(t *testing.T) {
			priv, err := rsa.GenerateKey(rand.Reader, bits)
			require.NoError(t, err)

			pub := &priv.PublicKey
			variant := VariantSHA384PSSDeterministic
			msg := []byte("key size test message")

			issueHandler, err := IssueHandler(IssuerConfig{
				Key:     priv,
				Variant: variant,
			})
			require.NoError(t, err)

			issuer := httptest.NewServer(issueHandler)
			defer issuer.Close()

			client, err := NewClient(ClientConfig{
				Key:           pub,
				Variant:       variant,
				TokenEndpoint: issuer.URL,
			})
			require.NoError(t, err)

			sig, state, err := client.ObtainSignature(context.Background(), msg)
			require.NoError(t, err)

			err = Verify(variant, pub, state.InputMessage(), sig)
			assert.NoError(t, err)
		})
	}
}

func TestEndToEndBlindnessProperty(t *testing.T) {
	priv, err := rsa.GenerateKey(rand.Reader, 2048)
	require.NoError(t, err)

	pub := &priv.PublicKey
	variant := VariantSHA384PSSDeterministic
	msg := []byte("blindness property test")

	prepared, err := Prepare(variant, rand.Reader, msg)
	require.NoError(t, err)

	blindedMsg1, state1, err := Blind(variant, pub, rand.Reader, prepared)
	require.NoError(t, err)

	blindedMsg2, state2, err := Blind(variant, pub, rand.Reader, prepared)
	require.NoError(t, err)

	assert.NotEqual(t, blindedMsg1, blindedMsg2, "blinded messages must differ")

	blindSig1, err := BlindSign(variant, priv, blindedMsg1)
	require.NoError(t, err)

	blindSig2, err := BlindSign(variant, priv, blindedMsg2)
	require.NoError(t, err)

	assert.NotEqual(t, blindSig1, blindSig2, "blind signatures must differ")

	sig1, err := Finalize(variant, pub, blindSig1, state1)
	require.NoError(t, err)

	sig2, err := Finalize(variant, pub, blindSig2, state2)
	require.NoError(t, err)

	err = Verify(variant, pub, state1.InputMessage(), sig1)
	assert.NoError(t, err)

	err = Verify(variant, pub, state2.InputMessage(), sig2)
	assert.NoError(t, err)
}

// RFC 9474 Appendix A test vectors.
func TestRFC9474Vectors(t *testing.T) {
	n, _ := new(big.Int).SetString("", 16)
	d, _ := new(big.Int).SetString("", 16)
	p, _ := new(big.Int).SetString("", 16)
	q, _ := new(big.Int).SetString("", 16)

	priv := &rsa.PrivateKey{
		PublicKey: rsa.PublicKey{N: n, E: 65537},
		D:         d,
		Primes:    []*big.Int{p, q},
	}
	priv.Precompute()
	pub := &priv.PublicKey

	inv, _ := new(big.Int).SetString("", 16)
	r := new(big.Int).ModInverse(inv, pub.N)

	t.Run("A.1 RSABSSA-SHA384-PSS-Randomized", func(t *testing.T) {
		verifyRFCVector(t, VariantSHA384PSSRandomized, pub, priv, r, inv, rfcVector{
			preparedMsg: "8417e699b219d583fb6216ae0c53ca0e9723442d02f1d1a34295527e7d929e8b8f3dc6fb8c4a02f4d6352edf0907822c1210a9b32f9bdda4c45a698c80023aa6b59f8cfec5fdbb36331372ebefedae7d",
			salt:        "051722b35f458781397c3a671a7d3bd3096503940e4c4f1aaa269d60300ce449555cd7340100df9d46944c5356825abf",
			encodedMsg:  "",
			blindedMsg:  "",
			blindSig:    "",
			sig:         "",
		})
	})

	t.Run("A.2 RSABSSA-SHA384-PSSZERO-Randomized", func(t *testing.T) {
		verifyRFCVector(t, VariantSHA384PSSZERORandomized, pub, priv, r, inv, rfcVector{
			preparedMsg: "84ea86c8cf3beedfed73beceabd792027c609d1100bf041fdd60d826a718130d8f3dc6fb8c4a02f4d6352edf0907822c1210a9b32f9bdda4c45a698c80023aa6b59f8cfec5fdbb36331372ebefedae7d",
			encodedMsg:  "",
			blindedMsg:  "",
			blindSig:    "",
			sig:         "",
		})
	})

	t.Run("A.3 RSABSSA-SHA384-PSS-Deterministic", func(t *testing.T) {
		verifyRFCVector(t, VariantSHA384PSSDeterministic, pub, priv, r, inv, rfcVector{
			preparedMsg: "8f3dc6fb8c4a02f4d6352edf0907822c1210a9b32f9bdda4c45a698c80023aa6b59f8cfec5fdbb36331372ebefedae7d",
			salt:        "051722b35f458781397c3a671a7d3bd3096503940e4c4f1aaa269d60300ce449555cd7340100df9d46944c5356825abf",
			encodedMsg:  "",
			blindedMsg:  "",
			blindSig:    "",
			sig:         "",
		})
	})

	t.Run("A.4 RSABSSA-SHA384-PSSZERO-Deterministic", func(t *testing.T) {
		verifyRFCVector(t, VariantSHA384PSSZERODeterministic, pub, priv, r, inv, rfcVector{
			preparedMsg: "8f3dc6fb8c4a02f4d6352edf0907822c1210a9b32f9bdda4c45a698c80023aa6b59f8cfec5fdbb36331372ebefedae7d",
			encodedMsg:  "",
			blindedMsg:  "",
			blindSig:    "",
			sig:         "",
		})
	})
}

type rfcVector struct {
	preparedMsg string
	salt        string
	encodedMsg  string
	blindedMsg  string
	blindSig    string
	sig         string
}

func verifyRFCVector(
	t *testing.T,
	variant Variant,
	pub *rsa.PublicKey,
	priv *rsa.PrivateKey,
	r, rInv *big.Int,
	tv rfcVector,
) {
	t.Helper()

	preparedMsg, err := hex.DecodeString(tv.preparedMsg)
	require.NoError(t, err)

	salt, err := hex.DecodeString(tv.salt)
	require.NoError(t, err)

	expectedEncodedMsg, err := hex.DecodeString(tv.encodedMsg)
	require.NoError(t, err)

	expectedBlindedMsg, err := hex.DecodeString(tv.blindedMsg)
	require.NoError(t, err)

	expectedBlindSig, err := hex.DecodeString(tv.blindSig)
	require.NoError(t, err)

	expectedSig, err := hex.DecodeString(tv.sig)
	require.NoError(t, err)

	// Step 1: Verify PSS encoding matches.
	mHash := sha512.Sum384(preparedMsg)
	emBits := pub.N.BitLen() - 1
	encoded, err := emsaPSSEncodeWithSalt(mHash[:], emBits, salt)
	require.NoError(t, err)
	assert.Equal(t, expectedEncodedMsg, encoded, "encoded message mismatch")

	// Step 2: Verify blinding matches.
	blindedMsg, state, err := fixedBlind(fixedBlindParams{
		variant:     variant,
		pub:         pub,
		preparedMsg: preparedMsg,
		salt:        salt,
		r:           r,
		rInv:        rInv,
	})
	require.NoError(t, err)
	assert.Equal(t, expectedBlindedMsg, blindedMsg, "blinded message mismatch")

	// Step 3: Verify blind signing matches.
	blindSig, err := BlindSign(variant, priv, blindedMsg)
	require.NoError(t, err)
	assert.Equal(t, expectedBlindSig, blindSig, "blind signature mismatch")

	// Step 4: Verify finalization matches.
	sig, err := Finalize(variant, pub, blindSig, state)
	require.NoError(t, err)
	assert.Equal(t, expectedSig, sig, "final signature mismatch")

	// Step 5: Verify the final signature.
	err = Verify(variant, pub, preparedMsg, sig)
	assert.NoError(t, err)
}

func keyName(bits int) string {
	switch bits {
	case 2048:
		return "RSA-2048"
	case 3072:
		return "RSA-3072"
	case 4096:
		return "RSA-4096"
	default:
		return "RSA-unknown"
	}
}
